INSERT INTO public.photos VALUES (25319, 'Pl. de la Constituciâ”śâ”‚n 1929', 'Plaza de la Constituciâ”śâ”‚n y paseo de la Independencia. Fuente visual: Foto Conrado Barlâ”śÂ®s, donada por Daniel Barlâ”śÂ®s y digitalizada por Josâ”śÂ® Luis Cintora para www.rafaelcastillejo.com', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65219100, -0.88102000, '0101000020E6100000C5E6E3DA5031ECBF6EDFA3FE7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23247423865.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23247423865.webp', 'https://www.flickr.com/photos/zaragozaantigua/23247423865/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25324, 'Plaza de la Constituciâ”śâ”‚n 1900', 'Hasta que en 1937 el nuevo consistorio nacionalista y digital, elegido a dedo entre partidarios del golpe de estado, impuso su cambio de denominaciâ”śâ”‚n, "de toda la vida", es decir, desde 1876, esta fue la plaza de la Constituciâ”śâ”‚n. Asâ”śÂˇ quedâ”śâ”‚ capturada por la fototipia de L. Escolâ”śĂ­ para su serie de preciosas postales "Zaragoza", resultando una instantâ”śĂ­nea de la plaza y el arranque de la calle de la Independencia en los â”śâ•‘ltimos momentos del siglo XIX (aâ”śâ–’o 1900). Fuente visual: www.delcampe.es/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65219700, -0.88107500, '0101000020E6100000A857CA32C431ECBF50C6F8307BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24023612701.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24023612701.webp', 'https://www.flickr.com/photos/zaragozaantigua/24023612701/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25325, 'Pl. de la Constituciâ”śâ”‚n 1916', 'Imagen de la plaza de la Constituciâ”śâ”‚n durante las fiestas mayores del aâ”śâ–’o 1916, capturada desde el nâ”¬â•‘ 31 del Coso, donde Gustav Freudental tenâ”śÂˇa entonces su estudio fotogrâ”śĂ­fico. A la derecha, andamios de obra del esquinero edificio entre la plaza y el paseo de la Independencia, remodelado segâ”śâ•‘n diseâ”śâ–’o de Miguel â”śĂĽngel Navarro. Al fondo, chimenea de la antigua Electra Peral Zaragozana, ya como parte de ERZ. Fuente: Foto Freudenthal, en "sombras.foto", Boletâ”śÂˇn de la Real Sociedad Fotogrâ”śĂ­fica de Zaragoza.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.65219700, -0.88107500, '0101000020E6100000A857CA32C431ECBF50C6F8307BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24050230304.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24050230304.webp', 'https://www.flickr.com/photos/zaragozaantigua/24050230304/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25993, 'Aeropuerto 2006', 'Vista aâ”śÂ®rea del aeropuerto de Zaragoza en 2006, antes de la construcciâ”śâ”‚n en 2008 de la nueva terminal de pasajeros. Arriba, la plataforma logâ”śÂˇstica PLAZA y el club de golf La Peâ”śâ–’aza. A la izquierda, el Canal Imperial y las instalaciones de la antigua terminal. Abajo, el barrio de Garrapinillos (izquierda) y la base aâ”śÂ®rea (derecha), que fue oficialmente estadounidense entre 1954 y 1992. Fuente: www.wikipedia.org', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.66084700, -1.03649900, '0101000020E61000002463B5F97F95F0BF71546EA296D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20132410652.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20132410652.webp', 'https://www.flickr.com/photos/zaragozaantigua/20132410652/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22818, 'Calle del Monasterio de Siresa 1973', 'Inâ”śÂ®dita imagen capturada en la calle del Monasterio de Siresa en el tramo comprendido entre las transversales calles del Doctor Iranzo, al fondo, y la de Salvador Minguijâ”śâ”‚n, a espaldas del fotâ”śâ”‚grafo. A la derecha, lado de los pares de este tramo, con la calzada y acera perfectamente pavimentadas, y a la izquierda aspecto de la mitad de la calle cuya urbanizaciâ”śâ”‚n corriâ”śâ”‚ a cargo del promotor inmobiliario que desarrollâ”śâ”‚ el lado de los impares en 1964... y que nueve aâ”śâ–’os despuâ”śÂ®s seguâ”śÂˇa tal cual. El aspecto visual mâ”śĂ­s llamativo es que a efectos de la circulaciâ”śâ”‚n rodada, esta calle llevaba demediada casi una dâ”śÂ®cada, algo muy poco probable de haber estado localizada en el "centro" urbano. Pero esto era un barrio, el de Las Fuentes, y por tanto no pasaba nada. Mientras tanto, unos bidones y cuatro vallas separan ambos lados de la calzada, y gracias.', 1973, 1973, 1973, 'Anos 70', 'LAS FUENTES', 41.64751800, -0.86302700, '0101000020E61000006A1492CCEA9DEBBF21C9ACDEE1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51606657333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51606657333.webp', 'https://www.flickr.com/photos/zaragozaantigua/51606657333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25333, 'Pl. de la Constituciâ”śâ”‚n 1928', 'Imagen de la plaza de la Constituciâ”śâ”‚n capturada por Foto Jalâ”śâ”‚n, y convertida en interesante postal por "Ediciones Unique". El telâ”śâ”‚n de fondo lo marcan los referenciales edificios que pivotan en torno a la Diputaciâ”śâ”‚n Provincial diseâ”śâ–’ada a mediados del XIX por Pedro Martâ”śÂˇnez Sangrâ”śâ”‚s. A sus flancos, el esquinero con el Coso ya habâ”śÂˇa sido remodelado hacâ”śÂˇa poco con proyecto de Teodoro Râ”śÂˇos, con su peculiar minarete-palomar; a la izquierda, el esquinero con el paseo de la Independencia tambiâ”śÂ®n habâ”śÂˇa sido modificado, la dâ”śÂ®cada anterior, con arreglo a diseâ”śâ–’o de Miguel â”śĂĽngel Navarro. En el espacio de la plaza, normalizada convivencia entre peatones, vehâ”śÂˇculos a tracciâ”śâ”‚n de sangre y de motor, y lâ”śÂˇneas de tranvâ”śÂˇa por doquiera. Quienes hoy viven con dolor por la presencia de una lâ”śÂˇnea del neo-tranvâ”śÂˇa, tras su reimplantaciâ”śâ”‚n en 2012 (habâ”śÂˇa sido erradicado en 1976), se hubieran consumido en la agonâ”śÂˇa, de haber vivido en la â”śÂ®poca de la Zaragoza de la imagen. Fuente visual: cortesâ”śÂˇa de www.ebay.es/', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.65219700, -0.88107500, '0101000020E6100000A857CA32C431ECBF50C6F8307BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26331927343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26331927343.webp', 'https://www.flickr.com/photos/zaragozaantigua/26331927343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25341, 'Pl. de la Constituciâ”śâ”‚n 1901', '"Saragosse. Un aragonais". Imagen de intrigante intercambio de miradas a la zaragozana, capturada en la plaza de la Constituciâ”śâ”‚n. Al fondo, la medianera entre la Farmacia Râ”śÂˇos. y la "Gran Peluquerâ”śÂˇa" que confrontaba con el Cafâ”śÂ® Oriental, en el emboque a la calle de los Mâ”śĂ­rtires. Fuente visual: www.delcampe.es/', 1901, 1901, 1901, 'Anos 1900', 'CENTRO', 41.65227400, -0.88048200, '0101000020E6100000FAEE5696E82CECBFFB03E5B67DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30035799291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30035799291.webp', 'https://www.flickr.com/photos/zaragozaantigua/30035799291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25342, 'Vista aâ”śÂ®rea plaza Espaâ”śâ–’a 1957', 'Vista aâ”śÂ®rea de la plaza de Espaâ”śâ–’a y su entorno. Destaca abajo la estructura circular del Teatro Circo, en la calle de San Miguel. Fuente: TAF Helicâ”śâ–“pters. Arxiu Nacional de Catalunya.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.65217800, -0.88107700, '0101000020E6100000D53F8864C831ECBFD99596917AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30549725183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30549725183.webp', 'https://www.flickr.com/photos/zaragozaantigua/30549725183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25343, 'Pl. de Espaâ”śâ–’a c.1966', 'Imagen capturada en el tramo del Coso recayente a la plaza de Espaâ”śâ–’a, y centrada en la entrada al Tubo por la calle de los Mâ”śĂ­rtires. Circula la unidad 303 en servicio en la lâ”śÂˇnea 11. Parque, encaminada hacia el antiguo Parque de Buenavista. Esta unidad serâ”śÂˇa desguazada en 1976, tras la clausura de la â”śâ•‘ltima lâ”śÂˇnea en activo de la histâ”śâ”‚rica red de tranvâ”śÂˇas urbanos. A la izquierda, esquina donde desde principios de siglo estuviera del Cafâ”śÂ® Oriental, y que pocos aâ”śâ–’os despuâ”śÂ®s conocerâ”śÂˇa la instalaciâ”śâ”‚n de la cafeterâ”śÂˇa Las Vegas 2. A la derecha, tras el tranvâ”śÂˇa, la farmacia Râ”śÂˇos, y ascendiendo adosados a los balcones, algunos de los anuncios comerciales que caracterizaban esta luminosa fachada del Coso. Fuente visual: John F. Bromley Archives, en www.flickr.com/photos/bear4922/32691790866/in/album-72157...', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65223700, -0.88088000, '0101000020E6100000556AF6402B30ECBFDE1E84807CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31202327627.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31202327627.webp', 'https://www.flickr.com/photos/zaragozaantigua/31202327627/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25344, 'Plaza de Espaâ”śâ–’a 1968', 'Imagen de una unidad de la serie 200 (posiblemente, la 216), subserie "Zaragoza", o "Rizados", de la lâ”śÂˇnea 11 "Parque-San Josâ”śÂ®", haciendo la curva de la plaza de Espaâ”śâ–’a para embocar luego el paseo de la Independencia. La seâ”śâ–’alâ”śÂ®tica indica que esta plaza habâ”śÂˇa sido convertida en un importante nudo para la circulaciâ”śâ”‚n rodada de larga distancia. Destaca una indicaciâ”śâ”‚n del "Museo Etnolâ”śâ”‚gico Teruel". Al fondo, emergen en el Coso las nuevas torres edilicias, y entre ellas, con su caracterâ”śÂˇstica cubierta de obra de la â”śÂ®poca (de caâ”śâ–’izo), el nuevo nâ”¬â•‘ 62 de la que fuera calle principal de la ciudad. A la izquierda, la antigua fachada del Coso antes de llegar a la calle Mâ”śĂ­rtires. Fuente visual: Foto Bernard Harrison, a travâ”śÂ®s de www.forotrenes.com/', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65243100, -0.88095600, '0101000020E610000015E126A3CA30ECBFC3F2E7DB82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31210554235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31210554235.webp', 'https://www.flickr.com/photos/zaragozaantigua/31210554235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25348, 'Pl. de Espaâ”śâ–’a 1965', 'Imagen de la plaza de Espaâ”śâ–’a con el reconocible telâ”śâ”‚n de fondo de los edificios del Coso. Uno de ellos, a la izquierda, de una entidad bancaria norteâ”śâ–’a, aparece con el andamiaje propio de la modernizaciâ”śâ”‚n en que estâ”śĂ­ en curso. Junto a â”śÂ®l, otra entidad bancaria pregona ser vitalicia, mas no. Fuente visual: Lala Ausfsberg, en www.bildindex.de/', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65245000, -0.88090600, '0101000020E6100000A4349BC76130ECBF3A234A7B83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32331496326.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32331496326.webp', 'https://www.flickr.com/photos/zaragozaantigua/32331496326/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23232, 'Schindler 2020', 'Imagen capturada en la calle de Albardâ”śÂˇn del Polâ”śÂˇgono Empresarium de La Cartuja Baja a principios del aâ”śâ–’o 2020, durante una concentraciâ”śâ”‚n de trabajadores de la fâ”śĂ­brica de ascensores de Schindler para protestar por las intenciones de la empresa en cerrar la planta de Zaragoza. En agosto cesâ”śâ”‚ la producciâ”śâ”‚n y en octubre la planta fue cerrada definitivamente. Los 114 â”śâ•‘ltimos trabajadores fueron despedidos de forma colectiva (ERE).', 2020, 2020, 2020, 'Siglo XXI', NULL, 41.57276900, -0.81908200, '0101000020E6100000B1C05774EB35EABFD1949D7E50C94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50696423056.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50696423056.webp', 'https://www.flickr.com/photos/zaragozaantigua/50696423056/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25355, 'Pl. de la Constituciâ”śâ”‚n 1929', 'Imagen realizada frente a las oficinas de "La Voz de Aragâ”śâ”‚n. Diario grâ”śĂ­fico independiente", sitas en el Coso nâ”¬â•‘ 37, justo entre el cafâ”śÂ® Royalty (nâ”¬â•‘ 35, a la izquierda) y el cafâ”śÂ® Oriental (nâ”¬â•‘ 39, a la derecha). La captura se centra en un llamativo automâ”śâ”‚vil de la casa La Licorne (modelo 5 caballos) que publicitaba en la ciudad el "gran concurso Los Artistas Enmascarados" patrocinado por los estudios norteamericanos de cine Metro Goldwyn Mayer, cuyo primer premio era, precisamente, este tentador y moderno vehâ”śÂˇculo. El diario La Voz de Aragâ”śâ”‚n fue fundado en 1925, y cerrâ”śâ”‚ sus puertas diez aâ”śâ–’os despuâ”śÂ®s. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65241800, -0.88079800, '0101000020E61000000C3B8C497F2FECBF2EA9DA6E82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34816682120.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34816682120.webp', 'https://www.flickr.com/photos/zaragozaantigua/34816682120/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25358, 'Plaza Constituciâ”śâ”‚n 1902', 'Comitiva del arzobispo Juan Soldevila el dâ”śÂˇa de su nombramiento, viernes 21 de marzo de 1902. Aparece en primer plano sobre una mula blanca. Detrâ”śĂ­s, fuente de la Princesa y basamento del monumento a los Mâ”śĂ­rtires, con andamios. Al fondo a la derecha, paseo de la Independencia.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65223700, -0.88088000, '0101000020E6100000556AF6402B30ECBFDE1E84807CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37330650804.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37330650804.webp', 'https://www.flickr.com/photos/zaragozaantigua/37330650804/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25361, 'Pl. de Espaâ”śâ–’a c.1955', 'Imagen capturada desde la altura del nâ”¬â•‘ 35 del Coso, con una buena vista de la plaza de Espaâ”śâ–’a y el arranque del antiguo paseo de la Independencia, que alcanza hasta la plaza de Paraâ”śÂˇso y el edificio Elâ”śÂˇseos como punto de inicio de los paseos de Calvo Sotelo y del General Mola. A la derecha, el moderno edificio del banco Hispano Americano. En primer tâ”śÂ®rmino, arbolada plaza de Espaâ”śâ–’a como nudo gordiano de las tranviarias lâ”śÂˇneas de Madrid, Torrero-Delicias, Ayuntamiento-Puerta Sancho y Parque. Fuente visual: Ediciones Garcâ”śÂˇa Garrabella, en www.delcampe.es', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65218700, -0.88118000, '0101000020E6100000FB743C66A032ECBF2CF015DD7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43307543941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43307543941.webp', 'https://www.flickr.com/photos/zaragozaantigua/43307543941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25370, 'Coso 1955', 'Imagen capturada en la plaza de Espaâ”śâ–’a con el objetivo del fotâ”śâ”‚grafo francâ”śÂ®s Jean Paul Margnac centrado en el arranque de la calle de los Mâ”śĂ­rtires que hacia la sombra del fondo se abre desde el Coso, donde se nos ofrece notable variedad de establecimientos comerciales (cafeterâ”śÂˇa, peluquerâ”śÂˇa de seâ”śâ–’oras, consulta dental, loterâ”śÂˇa...) y parroquia no menos variopinta, si bien predomina el traje chaqueta y falda larga, aun con la que estâ”śĂ­ cayendo. En primer tâ”śÂ®rmino, un guardia urbano se sale de su espacio de confort y se ubica allâ”śÂˇ donde la sombrilla le ofrece alguna protecciâ”śâ”‚n bajo la juliana canâ”śÂˇcula.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65236800, -0.88071900, '0101000020E610000008E8BE9CD92EECBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51241748635.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51241748635.webp', 'https://www.flickr.com/photos/zaragozaantigua/51241748635/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25374, 'Plaza de la Constituciâ”śâ”‚n c.1928', 'Imagen tomada junto al monumento a los Mâ”śĂ­rtires de la Religiâ”śâ”‚n y la Patria sito en la plaza de la Constituciâ”śâ”‚n, decorado con iluminaciones y motivos florales con motivo de las fiestas del Pilar. Al fondo, el edificio de la Diputaciâ”śâ”‚n Provincial.', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.65220100, -0.88080800, '0101000020E6100000F0C34142942FECBF91B586527BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53618506636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53618506636.webp', 'https://www.flickr.com/photos/zaragozaantigua/53618506636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25377, 'Plaza de la Constituciâ”śâ”‚n c.1900', 'Imagen capturada en la plaza de la Constituciâ”śâ”‚n y centrada en la Fuente de la Princesa como tradicional punto de encuentro social, tanto de usuarios y usuarias de su agua como de ciudadanos en general. Este hito urbano estaba descentrado respecto a la isleta peatonal que lo circunvalaba, rodeada de una doble fila de â”śĂ­rboles. Como telâ”śâ”‚n de fondo edilicio, fachadas de los inmuebles del Coso comprendidos entre el nâ”śâ•‘mero 29 y el 35.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65220100, -0.88104400, '0101000020E6100000E7C8CA2F8331ECBF91B586527BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54639488244.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54639488244.webp', 'https://www.flickr.com/photos/zaragozaantigua/54639488244/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25662, 'Calle de los Estâ”śÂ®banes 2005', 'Aspecto de la calle de los Estâ”śÂ®banes del Tubo de Zaragoza en 2005. Fuente: Artigrama, 2005.', 2005, 2005, 2005, 'Siglo XXI', 'CENTRO', 41.65323300, -0.87973300, '0101000020E610000071C806D2C526ECBF80D591239DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19585156205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19585156205.webp', 'https://www.flickr.com/photos/zaragozaantigua/19585156205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25672, 'Calle Cuatro de Agosto 2005', 'Foto: Marina Ovejero. Aspecto fâ”śâ•‘nebre de las calles del Tubo. En este caso, la del Cuatro de Agosto, tramo comprendido entre Libertad y Mâ”śĂ­rtires. La agonâ”śÂˇa lenta y programada de esta zona de la ciudad venâ”śÂˇa prolongâ”śĂ­ndose desde los aâ”śâ–’os ochenta, derribo tras derribo, solar tras solar, a la espera de una â”śÂ®poca boyante para el negocio inmobiliario. Constructores y Ayuntamiento, en una entente cordial, miraban para otro lado mientras la zona se degradaba. A partir de 2005, el cadâ”śĂ­ver resucitâ”śâ”‚ con nueva piel y brâ”śÂˇos modernos, al son de la burbuja inmobiliaria que pronto explotarâ”śÂˇa. Fuente visual: Heraldo de Aragâ”śâ”‚n.', 2005, 2005, 2005, 'Siglo XXI', 'CENTRO', 41.65291800, -0.88028100, '0101000020E61000001F49490F432BECBF207C28D192D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30981908264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30981908264.webp', 'https://www.flickr.com/photos/zaragozaantigua/30981908264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25679, 'Calle de la Libertad 2005', 'Imagen de la adintelada puerta de ingreso al antiguo inmueble del nâ”śâ•‘mero 6 de la calle de la Libertad. como monumental marco escâ”śÂ®nico del ruinoso panorama dejado por el derribo de algunas de las grandes casas de la zona realizado en el â”śâ•‘ltimo cuarto del pasado siglo XX, como esta misma, la de Teresa Ciprâ”śÂ®s de la calle de los Estâ”śÂ®banes, y la de la condesa de Aranda de la calle de Cinegio. Resultado de ello es esta despejada visual de la iglesia parroquial de San Gil Abad y de la fachada del nâ”¬â•‘ 27 de la calle de los Estâ”śÂ®banes (izquierda), en cuyos bajos estuviera el cine Latino. Aâ”śâ–’os despuâ”śÂ®s, algunos de estos solares serâ”śÂˇan convertidos en terrazas vinculadas a establecimientos de hostelerâ”śÂˇa. Fuente visual: foto Josâ”śÂ® Marâ”śÂˇa Ballestâ”śÂˇn Miguel.', 2005, 2005, 2005, 'Siglo XXI', 'CENTRO', 41.65320400, -0.88042800, '0101000020E61000002E724F57772CECBFE6CE4C309CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43416158872.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43416158872.webp', 'https://www.flickr.com/photos/zaragozaantigua/43416158872/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25681, 'Calle de los Mâ”śĂ­rtires 1964', 'Imagen capturada en la calle de los Mâ”śĂ­rtires con el fondo de la plaza de Espaâ”śâ–’a.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65247300, -0.88056900, '0101000020E6100000B5E21B0A9F2DECBFF2423A3C84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51011801038.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51011801038.webp', 'https://www.flickr.com/photos/zaragozaantigua/51011801038/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25899, 'Plaza de la Constituciâ”śâ”‚n c.1912', 'Los tranvâ”śÂˇas circulan custodiados, tal que la imagen, que captura un "Primitivo", o primera serie de tranvâ”śÂˇas elâ”śÂ®ctricos de la ciudad, de Carde y Escoriaza. El escenario es el giro de las vâ”śÂˇas en la plaza de la Constituciâ”śâ”‚n para embocar el paseo de la Independencia. Los edificios del fondo son los que hacâ”śÂˇan esquina con el Coso Alto. La referencia mâ”śĂ­s destacada de esta foto suele ser que el tranvâ”śÂˇa es conducido por una mujer.', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.65239700, -0.88106400, '0101000020E6100000ADDA3521AD31ECBF1781B1BE81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15638629166.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15638629166.webp', 'https://www.flickr.com/photos/zaragozaantigua/15638629166/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25933, 'Pl. de la Constituciâ”śâ”‚n 1905', 'Luminosa imagen de la plaza de la Constituciâ”śâ”‚n capturada desde la altura del nâ”śâ•‘mero 49 del Coso con una interesante panorâ”śĂ­mica del antiguo frontal angular oeste de la plaza, conformado de derecha a izquierda por los inmuebles de los nâ”śâ•‘meros 1 (en cuyos bajos estaba el cafâ”śÂ® Gambrinus), 2 (decimonâ”śâ”‚nica Diputaciâ”śâ”‚n Provincial de Zaragoza), y 3 (en cuyos bajos estaba el cafâ”śÂ® Suizo). En primer tâ”śÂ®rmino, a la derecha, dos unidades tranviarias de la etapa de coexistencia entre los modernos tranvâ”śÂˇas elâ”śÂ®ctricos (a la izquierda, un "Primitivo" posiblemente en servicio en la lâ”śÂˇnea "Arrabal"), y los antiguos tranvâ”śÂˇas de tracciâ”śâ”‚n animal (a la derecha, un Coche Cerrado tipo "C") reconvertidos en remolques. Al fondo, a la izquierda, uno de los dos evacuatorios de la â”śÂ®poca ubicados en el arranque del paseo de la Independencia. Fuente visual: Fototipia Madriguera (Barcelona), en www.delcampe.es', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.65223700, -0.88077300, '0101000020E6100000D464C6DB4A2FECBFDE1E84807CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42465155715.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42465155715.webp', 'https://www.flickr.com/photos/zaragozaantigua/42465155715/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25990, 'Pl. de la Constituciâ”śâ”‚n 1925', 'Vista aâ”śÂ®rea de Zaragoza, con la plaza de la Constituciâ”śâ”‚n y alrededores. En la esquina superior izquierda, cuartel de artillerâ”śÂˇa del Carmen; contiguos, los lavaderos de Castellvâ”śÂˇ y el Hospital Militar, junto a la iglesia de Santiago, antiguo convento de San Ildefonso. Fuente: www.facebook.com/photo.php?fbid=896445793734761&set=g...', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65227400, -0.88092300, '0101000020E6100000276A696E8530ECBFFB03E5B67DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19648308821.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19648308821.webp', 'https://www.flickr.com/photos/zaragozaantigua/19648308821/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20906, 'Incendio Coliseo de Comedias 1778', 'El Coliseo de Comedias de Zaragoza en llamas o Incendio del teatro de Zaragoza la noche del 12 de noviembre de 1778. Atribuido a Francisco de Goya. "La tarde del 12 de noviembre de 1778 se produjo un pavoroso incendio en el Coliseo de Zaragoza que terminâ”śâ”‚ ardiendo por completo. El cronista de la ciudad, Tomâ”śĂ­s Sebastiâ”śĂ­n y Latre, nos ha dejado el testimonio mâ”śĂ­s acabado del suceso, dâ”śĂ­ndonos cuenta de la consternaciâ”śâ”‚n que causâ”śâ”‚. Pero a la desgracia se acercaron tambiâ”śÂ®n diversos creadores, poetas los mâ”śĂ­s, junto a detractores de los espectâ”śĂ­culos teatrales. Entre los primeros encontramos vates de cierto reconocimiento como el Padre Boggiero o el salmantino Iglesias de la Casa; entre los segundos, grandes predicadores del momento, como Fray Diego de Câ”śĂ­diz, el Padre Garcâ”śÂ®s y el Padre Bruno. Entre unos y otros nos dan un veraz panorama de câ”śâ”‚mo era la sociedad en la que se moviâ”śâ”‚ Francisco de Goya y Lucientes a quien, por cierto, se le atribuye una tabla al â”śâ”‚leo sobre el motivo del incendio teatral. El Coliseo abatido habâ”śÂˇa sido inaugurado en 1771. Estaba situado en el solar que hoy en dâ”śÂˇa ocupa el Banco de Espaâ”śâ–’a. Estaba pegado al edificio del Hospital y llegaba hasta la que no hace mucho se denominaba como calle de los Sitios." Ernesto Viamonte Lucientes', 1778, 1778, 1778, 'Siglo XIX', 'CENTRO', 41.65191100, -0.88027900, '0101000020E6100000F2608BDD3E2BECBF8A73D4D171D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14999276472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14999276472.webp', 'https://www.flickr.com/photos/zaragozaantigua/14999276472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20912, 'Coliseo de Comedias 1771', 'Planta del Coliseo de Comedias de Zaragoza, inaugurado en 1771. Se accedâ”śÂˇa a â”śÂ®l por el Coso, estaba adosado al complejo hospitalario de Nâ”¬Â¬ Sâ”¬Â¬ de Gracia, y a su izquierda (mirando desde el Coso) se abrâ”śÂˇa la calle de la Soledad (luego, de los Sitios, actual Josefa Amar). Era uno de los mâ”śĂ­s elegantes y amplios del Reino, con capacidad para unas 1300 personas distribuidas en 4 pisos. Un pavoroso incendio accidental acabâ”śâ”‚ con â”śÂ®l apenas 7 aâ”śâ–’os despuâ”śÂ®s, en medio de la representaciâ”śâ”‚n operâ”śÂˇstica de "La real jura de Artaxerjes", provocando 60 personas muertas, y 52 heridas. Hasta 1799, en que se inaugurâ”śâ”‚ el "Teatro Nuevo", actual Principal, la ciudad careciâ”śâ”‚ de un hogar fijo para Talâ”śÂˇa y Melpâ”śâ”‚mene. Fuente visual: Jaime Latas Fuertes, "La ocupaciâ”śâ”‚n francesa de Zaragoza (1809-1813), As. Cultural "Los Sitios de Zaragoza", 2012. Fuente textual: Ernesto Viamonte Lucientes, "El Coliseo de Comedias de Zaragoza en llamas: â”śâ”‚leo de Goya y signo de su tiempo", IFC, 2013.', 1771, 1771, 1771, 'Siglo XIX', 'CENTRO', 41.65191100, -0.88027900, '0101000020E6100000F2608BDD3E2BECBF8A73D4D171D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16103152697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16103152697.webp', 'https://www.flickr.com/photos/zaragozaantigua/16103152697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20913, 'Joan Thomas Porcell 1565', 'Joan Thomas Porcell. "Informaciâ”śâ”‚n y Curaciâ”śâ”‚n de la peste de Zaragoâ”śÂşa y preservaciâ”śâ”‚n contra la peste en general", Zaragoza. Viuda de Bartholome de Nagera, 1565. Naciâ”śâ”‚ en 1528 en Cagliari (Câ”śâ”‚rcega), cursâ”śâ”‚ Medicina en Salamanca, y la ejerciâ”śâ”‚ en Zaragoza ademâ”śĂ­s de ser catedrâ”śĂ­tico en el Estudio General previo a la Universidad. En 1564 una tremenda epidemia de peste negra se propagâ”śâ”‚ en Zaragoza, y Porcell se hizo cargo, ante la deserciâ”śâ”‚n de buena parte de los cirujanos y mâ”śÂ®dicos de la ciudad, de los ochocientos apestados del Hospital de Nuestra Seâ”śâ–’ora de Gracia. De lo vivido en esas circunstancias, este doctor escribiâ”śâ”‚ un libro con el tâ”śÂˇtulo que abre la entrada. En â”śÂ®l expone de modo sistemâ”śĂ­tico las cuestiones relacionadas con la naturaleza, la clâ”śÂˇnica, la terapâ”śÂ®utica, la prevenciâ”śâ”‚n y la asistencia de la enfermedad. Es considerada una de las cumbres de la epidemiologâ”śÂˇa renacentista. En la imagen, el doctor Porcell realizando una autopsia en el antiguo Hospital de Gracia a una fallecida por peste.', 1565, 1565, 1565, 'Siglo XIX', 'CENTRO', 41.65159900, -0.88057900, '0101000020E6100000986BD102B42DECBF9B8D959867D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16590356047.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16590356047.webp', 'https://www.flickr.com/photos/zaragozaantigua/16590356047/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20916, 'Cruz del Coso 1541', 'Detalle de la sillerâ”śÂˇa del coro del Pilar de Zaragoza, Esteban de Obray, 1541. Representa la legendaria muerte de los mâ”śĂ­rtires de la ciudad, incluido san Lamberto (en primer plano, con la cabeza en la mano), en el espacio ocupado por la actual plaza de Espaâ”śâ–’a. La importancia de esta talla reside en la representaciâ”śâ”‚n, al fondo, de la llamada "Cruz del Coso", templete redondo de piedra del siglo XV con una cruz en el centro, que se levantaba en ese espacio periurbano, en conmemoraciâ”śâ”‚n del episodio. Fue destruido en el Sitio de 1808, tras varias reedificaciones. Fuente visual: eszaragoza.blogspot.com.es/2014/05/la-crus-del-coso-en-za...', 1541, 1541, 1541, 'Siglo XIX', 'CENTRO', 41.65214200, -0.88072000, '0101000020E61000001EDC9DB5DB2EECBF8C2C996379D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19074950192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19074950192.webp', 'https://www.flickr.com/photos/zaragozaantigua/19074950192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20918, 'Hospital de Nuestra Seâ”śâ–’ora de Gracia 1778', 'Real y General Hospital de Nuestra Seâ”śâ–’ora de Gracia de Zaragoza (derecha) y Casa de Comedias al Coso (izquierda) a finales del siglo XVIII. Dibujo incluido en "El Hospital Real y General de Nuestra Seâ”śâ–’ora de Gracia de Zaragoza en el siglo XVIII", tesis doctoral de Asunciâ”śâ”‚n Fernâ”śĂ­ndez Doctor, publicada por la IFC en 1987. Fuente: enfeps.blogspot.com.es/2014/12/la-enfermeria-en-zaragoza-...', 1778, 1778, 1778, 'Siglo XIX', 'CENTRO', 41.65179100, -0.88049400, '0101000020E61000000B60CAC0012DECBFE06932E36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19375108618.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19375108618.webp', 'https://www.flickr.com/photos/zaragozaantigua/19375108618/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20936, 'Incendio Hospital 1778', '"Incendio de un hospital". â”śĂ´leo sobre lienzo, Francisco de Goya, ca. 1808-1812. Museo Nacional de Bellas Artes, Buenos Aires. Un grupo de personas huye de las llamas de un edificio. Una mujer es transportada en camilla. Segâ”śâ•‘n algunos autores, como Marâ”śÂˇa Teresa Miralles, este cuadro hace referencia al incendio que destruyâ”śâ”‚ el Teatro de Comedias del Hospital de Nuestra Seâ”śâ–’ora de Gracia el 12 de noviembre de 1778, muriendo 77 personas. Este teatro fue levantado en el siglo XVI en el Coso para financiar el hospital y sustituido por el nuevo Coliseo de Comedias en 1771. Tras el incendio, Zaragoza no tuvo teatro estable hasta 1799, con la inauguraciâ”śâ”‚n enfrente del Teatro Nuevo del arquitecto Agustâ”śÂˇn Sanz, hoy Teatro Principal. Fuente visual: www.bellasartes.gob.ar Fuente textual: Incendio en un hospital en el siglo XVIII. Anâ”śĂ­lisis del acontecimiento descrito por Francisco Josâ”śÂ® de Goya y Lucientes, 2009, en scielo.isciii.es/', 1778, 1778, 1778, 'Siglo XIX', 'CENTRO', 41.65179300, -0.88028300, '0101000020E61000004D310741472BECBF8061F9F36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32682811955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32682811955.webp', 'https://www.flickr.com/photos/zaragozaantigua/32682811955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20972, 'Pl. de San Fernando 1852', '"The Fete of Notre Dame del Pilar, at Saragossa", xilografâ”śÂˇa de Alenjo Valentâ”śÂˇn para Illustrated London News, Londres, 1952. Es octubre de 1952 y se celebran en Zaragoza las Fiestas del Pilar. La plaza de San Francisco, luego de San Fernando y despuâ”śÂ®s de la Constituciâ”śâ”‚n (hoy de Espaâ”śâ–’a) alberga la procesiâ”śâ”‚n que vemos, desde la actual posiciâ”śâ”‚n del Banco de Espaâ”śâ–’a. A la derecha, la calle Don Jaime I, con un edificio en su esquina derecha que es el mismo que hay hoy; al fondo de esta calle, la torre de San Gil.', 1852, 1852, 1852, 'Siglo XIX', 'CENTRO', 41.65207800, -0.88104200, '0101000020E6100000B9E00CFE7E31ECBF7638BA4A77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19320367989.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19320367989.webp', 'https://www.flickr.com/photos/zaragozaantigua/19320367989/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20988, 'Coso 1808', 'Dibujo recreando el tramo del Coso desde la iglesia del Hospital de Nuestra Seâ”śâ–’ora de Gracia, cuyo acceso queda a la izquierda, pasando por la calle del Hospital, o de Santa Engracia, y el enorme convento de San Francisco, cuya alta torre despunta a la izquierda, junto la destacable nave de la iglesia conventual franciscana, cuyo acceso principal se realizaba desde la pequeâ”śâ–’a plaza de San Francisco, a travâ”śÂ®s de la portada abocinada y rematada en tres pequeâ”śâ–’as torres del centro de la imagen. A su derecha, el tramo del Coso con los palacios de Sâ”śĂ­stago, del marquâ”śÂ®s de Campo Franco, y del Conde de Fuentes, hasta el Arco de San Roque. El autor del dibujo es Josâ”śÂ® Galiay, y es posible que para su realizaciâ”śâ”‚n se hubiera basado en el grabado "Vista de la calle del Coso", de Juan Gâ”śĂ­lvez y Fernando Brambila, realizado en 1812-1813. La peculiaridad de este dibujo serâ”śÂˇa tratar de mostrar el aspecto de la zona antes de los asedios de 1808-1809. Fuente visual: www.mecd.gob.es/.', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65200200, -0.88073900, '0101000020E6100000CFF9298E032FECBF9B7631CD74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24595800011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24595800011.webp', 'https://www.flickr.com/photos/zaragozaantigua/24595800011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21070, 'Calle San Gil 1871', '"Zaragoza. Arco levantado en la calle de San Gil por la tertulia progresista, y procesiâ”śâ”‚n de los gigantones", Xilografâ”śÂˇa, Revista La ilustraciâ”śâ”‚n Espaâ”śâ–’ola y Americana, 1871. Festejos con motivo de la visita del rey Amadeo I de Saboya a Zaragoza en 1871.', 1871, 1871, 1871, 'Siglo XIX', 'CENTRO', 41.65196800, -0.88012900, '0101000020E61000009F5BE84A042AECBFEE04FBAF73D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19016004752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19016004752.webp', 'https://www.flickr.com/photos/zaragozaantigua/19016004752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21137, 'El dios de las aguas 1890', 'Joaquâ”śÂˇn Pallarâ”śÂ®s: El dios de las aguas en Zaragoza, â”śâ”‚leo/lienzo, 1890 Actual plaza de Espaâ”śâ–’a con la fuente de la Princesa en 1890.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65206900, -0.88084100, '0101000020E6100000DE3AFF76D92FECBF22DE3AFF76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14688543558.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14688543558.webp', 'https://www.flickr.com/photos/zaragozaantigua/14688543558/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21227, 'Pl. de la Constituciâ”śâ”‚n 1903', 'Plaza de la Constituciâ”śâ”‚n de Zaragoza, momentos antes de la llegada del rey Alfonso XIII el 16 de octubre de 1903. Hasta su inauguraciâ”śâ”‚n en 1904, el pedestal del Monumento a los Mâ”śĂ­rtires esperaba la instalaciâ”śâ”‚n del conjunto escultâ”śâ”‚rico, siendo utilizado para sostener otros ornatos, como es el caso: "corona monumental adornada con 1.600 bombillas de colores". Fuente: Revista La Hormiga de Oro.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65207800, -0.88104200, '0101000020E6100000B9E00CFE7E31ECBF7638BA4A77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18524290153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18524290153.webp', 'https://www.flickr.com/photos/zaragozaantigua/18524290153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21230, 'Plaza Constituciâ”śâ”‚n 1903', '"Arco de la Real Maestranza y Pedestal de los Mâ”śĂ­rtires de la Independencia". Alfonso XIII visitâ”śâ”‚ Zaragoza entre el 16 y el 19 de octubre de 1903. La aristocracia local organizada en torno a la Real Maestranza encargâ”śâ”‚ su arco al ingeniero Manuel de Isasi Isasmendi, en la entrada al paseo desde la plaza de la Constituciâ”śâ”‚n, frente por frente con el aâ”śâ•‘n sin terminar monumento a los Mâ”śĂ­rtires de la Religiâ”śâ”‚n (catâ”śâ”‚lica) y de la Patria (espaâ”śâ–’ola). Su pedestal tambiâ”śÂ®n fue engalanado para la ocasiâ”śâ”‚n, a falta de conjunto escultâ”śâ”‚rico. El gran arco ultrasemicircular abocinado fue decorado con bicâ”śÂ®falas â”śĂ­guilas imperiales y leones. Tras los fastos, fue desmontado. Fuente: Revista Nuevo Mundo.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65207800, -0.88104200, '0101000020E6100000B9E00CFE7E31ECBF7638BA4A77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19132300591.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19132300591.webp', 'https://www.flickr.com/photos/zaragozaantigua/19132300591/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21275, 'Cine Coyne 1905', 'Cartel anunciador del Cine Parlante Coyne, sito en la calle de San Miguel 3. Se trataba de una de las primeras salas estables de cine de la ciudad, y fue inaugurado por Ignacio Coyne en 1905, permaneciendo hasta 1910. Fuente visual: DARA/AHPZ.', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.65123700, -0.88105200, '0101000020E61000009C69C2F69331ECBFFB78E8BB5BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23434707000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23434707000.webp', 'https://www.flickr.com/photos/zaragozaantigua/23434707000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26052, 'Râ”śÂˇo Ebro 2006', 'Ortofoto obtenida el 1 de agosto de 2006. Muestra el paso del râ”śÂˇo Ebro por Zaragoza, con los puentes de Santiago, de Piedra y del Pilar. Fuente: Gobierno de Aragâ”śâ”‚n. Departamento de Presidencia y Relaciones Institucionales. Centro de Documentaciâ”śâ”‚n e Informaciâ”śâ”‚n Territorial de Aragâ”śâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HISTâ”śĂ´RICO', 41.65657000, -0.87354600, '0101000020E6100000D7A6B1BD16F4EBBF72C45A7C0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32059405996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32059405996.webp', 'https://www.flickr.com/photos/zaragozaantigua/32059405996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21349, 'Plaza de la Constituciâ”śâ”‚n 1903', 'Imagen capturada en la plaza de la Constituciâ”śâ”‚n con el objetivo centrado en el decimonâ”śâ”‚nico edificio de la Diputaciâ”śâ”‚n provincial. A la izquierda y fuera de plano queda la Fuente de la Princesa, circunvalada por la gran glorieta jalonada por â”śĂ­rboles reciâ”śÂ®n podados segâ”śâ•‘n orden municipal. Sobre el embarrado firme transita una berlina tirada por una caballerâ”śÂˇa, carruaje especialmente recomendable durante los frâ”śÂˇos meses del invierno.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65212900, -0.88104400, '0101000020E6100000E7C8CA2F8331ECBFF8E28BF678D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54200357707.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54200357707.webp', 'https://www.flickr.com/photos/zaragozaantigua/54200357707/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21386, 'Calle de Los Sitios 1915', '"Una amiga del Heraldo: Un baturro comprando el extraordinario a la veterana vendedora ''La Castellana'', una de las expendedoras de periâ”śâ”‚dicos mâ”śĂ­s antiguas". Imagen tomada en la confluencia de la calle de Los Sitios (actual de Josefa Amar y Borbâ”śâ”‚n) con el tramo medio del Coso al fondo.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65189400, -0.87982900, '0101000020E6100000F850A2258F27ECBFB43A394371D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18979076494.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18979076494.webp', 'https://www.flickr.com/photos/zaragozaantigua/18979076494/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21389, 'Pl. de la Constituciâ”śâ”‚n 1913', 'Foto Luis Gandâ”śâ•‘ Mercadal, 1913. Tranvâ”śÂˇa conducido por la Guardia Civil en la plaza de la Constituciâ”śâ”‚n, con motivo de una huelga. Al fondo, el Coso Medio y el Hotel Europa. Fuente: patrimoniocultural.unizar.es/node/1906', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65196600, -0.88066600, '0101000020E6100000525F96766A2EECBF4E0D349F73D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19880363658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19880363658.webp', 'https://www.flickr.com/photos/zaragozaantigua/19880363658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22846, 'Salvador Minguijâ”śâ”‚n 1989', 'Foto â”śĂĽnchel Lâ”śâ”‚pez, 13/8/1989. Calle de Salvador Minguijâ”śâ”‚n el el barrio de Las Fuentes. Al fondo, actual Echegaray y Caballero y orillas del Ebro, sin urbanizar. Toma realizada desde la esquina de la calle Tiermas con Salvador MInguijâ”śâ”‚n. Se distinguen las entradas a las calles Azorâ”śÂˇn (izquierda) y Comuneros de Castilla (derecha). Fuente: www.facebook.com/photo.php?fbid=10204905411053632&set...', 1989, 1989, 1989, 'Anos 80', 'LAS FUENTES', 41.65080300, -0.86096700, '0101000020E61000006CED7DAA0A8DEBBFC19140834DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15135163460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15135163460.webp', 'https://www.flickr.com/photos/zaragozaantigua/15135163460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21448, 'Coso Medio c.1912', 'Luminosa imagen capturada desde el mar de vâ”śÂˇas de la plaza de la Constituciâ”śâ”‚n y orientada hacia el oriente, hacia el tramo medio del Coso donde una unidad de la tranviaria serie 20 se encamina hacia la calle de Don Jaime I, posiblemente en servicio en la lâ”śÂˇnea del Arrabal. A su derecha, un remolque reutilizado de las antiguas unidades de tracciâ”śâ”‚n animal, y un coche de caballo estacionado junto al Gran Hotel de Europa. A la izquierda y en primer tâ”śÂ®rmino, un carro cargado porta un jergâ”śâ”‚n metâ”śĂ­lico, entre otros enseres. La convivencia entre vehâ”śÂˇculos y peatones muestra que el trâ”śĂ­fico estaba bastante pacificado en esta â”śÂ®poca, tal vez por la ausencia de modernos automâ”śâ”‚viles. Câ”śâ”‚mo serâ”śĂ­ la cosa, que hasta el Coso parece mâ”śĂ­s ancho, aunque es mâ”śĂ­s probable que eso se deba a la escala humana de los edificios que lo jalonaban.', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.65214400, -0.88042900, '0101000020E610000045662E70792CECBF2D24607479D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49992554481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49992554481.webp', 'https://www.flickr.com/photos/zaragozaantigua/49992554481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21449, 'Plaza de la Constituciâ”śâ”‚n 1913', 'Nocturna imagen capturada desde la altura del inmueble del nâ”¬â•‘ 43-45 del Coso durante un espectacular lanzamiento de fuegos artificiales en la plaza de la Constituciâ”śâ”‚n durante las Fiestas del Pilar de ese aâ”śâ–’o. Entre el numeroso gentâ”śÂˇo asistente destaca un florido y efâ”śÂˇmero arco triunfal en primer tâ”śÂ®rmino, y el Monumento a los Mâ”śĂ­rtires de la Religiâ”śâ”‚n y la Patria. Al fondo, fachada del edificio de la Diputaciâ”śâ”‚n Provincial.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65192700, -0.88113700, '0101000020E61000002975C9384632ECBF90300C5872D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50246109067.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50246109067.webp', 'https://www.flickr.com/photos/zaragozaantigua/50246109067/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21463, 'Plaza de la Constituciâ”śâ”‚n 1915', 'Inâ”śÂ®dita imagen capturada a la sombra del reciente Monumento a los mâ”śĂ­rtires de la religiâ”śâ”‚n y de la patria que desde 1904 centra la plaza de la Constituciâ”śâ”‚n, con una vista orientada hacia la fachada del Coso comprendida desde el nâ”śâ•‘mero 43, el arranque de la calle de Don Jaime I y el tramo medio del Coso que aquâ”śÂˇ se alcanza hasta el edificio del Banco de Espaâ”śâ–’a. A la derecha, gran inmueble del nâ”¬â•‘ 8 de la plaza donde estaba emplazado el prestigioso Hotel Europa, en cuya esquina destaca atoldado uno de los antiguos quioscos luego eliminados tras una remodelaciâ”śâ”‚n urbana de este espacio. A la izquierda y sobre el calzada, dos unidades de la serie "Primitivos" del tranvâ”śÂˇa, ambos construidos en los talleres de Carde y Escoriaza y posiblemente en servicio en las lâ”śÂˇneas "Circunvalaciâ”śâ”‚n" y "Bajo Aragâ”śâ”‚n". Aparte de ellos, el trâ”śĂ­nsito se muestra muy pacâ”śÂˇfico.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65201600, -0.88083700, '0101000020E6100000836A8313D12FECBF003CA24275D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52430604682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52430604682.webp', 'https://www.flickr.com/photos/zaragozaantigua/52430604682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21492, 'Entierro Soldevila 1923', '"El entierro del Cardenal Soldevila", 08/06/1923. Soldevila, el famoso arzobispo de Zaragoza (desde 1902), fue asesinado el 4 de junio en la finca de recreo de "El Terminillo", donde habâ”śÂˇa fundado unas escuelas-asilo en 1914. Su gran popularidad se debâ”śÂˇa a que conjugaba, como si de una sola cosa se tratara, la cara religiosa con la institucional: era tambiâ”śÂ®n Senado desde 1898r, y desde esa faceta opinaba de todo lo humano desde un punto de vistas ultraconservador, ademâ”śĂ­s de sintonizar notoriamente con la emergente extrema derecha polâ”śÂˇtica en lo relacionado con cuestiones sociales y econâ”śâ”‚micas. Su muerte por asesinato se inscribe en las violentas luchas sociales de la â”śÂ®poca. Fue antolâ”śâ”‚gica la enorme manifestaciâ”śâ”‚n de duelo en Zaragoza con motivo de su entierro en el Pilar, cuyas obras habâ”śÂˇa impulsado al lograr su declaraciâ”śâ”‚n como Monumento Nacional. Un joven seminarista de la residencia de San Carlos, de nombre Josâ”śÂ® Marâ”śÂˇa Escrivâ”śĂ­, estaba entre el pâ”śâ•‘blico asistente. En la imagen, la plaza de la Constituciâ”śâ”‚n al paso del cortejo funerario. A la izquierda, el Coso medio.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65208800, -0.88104300, '0101000020E6100000D0D4EB168131ECBF990E9D9E77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15221763549.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15221763549.webp', 'https://www.flickr.com/photos/zaragozaantigua/15221763549/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
